import { createNoise2D, createNoise3D } from 'simplex-noise';
import { gameStore } from '../store';
import { BLOCK_TYPES } from '../types';

const CHUNK_SIZE = 16;
const WATER_LEVEL = 4;

// Simple seeded random to create the noise functions
function alea(seed: number) {
  let s = seed;
  return function() {
    s = Math.sin(s) * 10000;
    return s - Math.floor(s);
  };
}

let noise2D: ReturnType<typeof createNoise2D>;
let noise3D: ReturnType<typeof createNoise3D>;
let globalSeed = 0;

export function initTerrainGenerator(seed: number) {
  globalSeed = seed;
  const prng = alea(seed);
  noise2D = createNoise2D(prng);
  noise3D = createNoise3D(prng);
}

function hash2D(x: number, z: number, seed: number) {
  const h = Math.sin(x * 12.9898 + z * 78.233 + seed) * 43758.5453123;
  return h - Math.floor(h);
}

export function getTerrainHeightAndType(x: number, z: number) {
  if (!noise2D) return { height: 10, biome: 'forest' };
  
  const elNoise = noise2D(x * 0.015, z * 0.015);
  const detailNoise = noise2D(x * 0.05, z * 0.05) * 0.2;
  const height = Math.floor((elNoise + detailNoise + 1.0) * 8) + 5;
  
  const moisture = (noise2D(x * 0.02, z * 0.02) + 1.0) * 0.5;
  
  let biome = 'forest';
  if (height >= 15) {
    biome = 'mountain';
  } else if (moisture < 0.38) {
    biome = 'desert';
  }
  
  return { height, biome };
}

export function generateChunk(chunkX: number, chunkZ: number) {
  const blocks: { position: [number, number, number], type: number }[] = [];
  
  if (!noise2D) return blocks;

  const chunkStartX = chunkX * CHUNK_SIZE;
  const chunkStartZ = chunkZ * CHUNK_SIZE;

  // 1. Generate base terrain
  const terrainGrid: Record<string, number> = {};

  for (let x = 0; x < CHUNK_SIZE; x++) {
    for (let z = 0; z < CHUNK_SIZE; z++) {
      const globalX = chunkStartX + x;
      const globalZ = chunkStartZ + z;
      
      const { height, biome } = getTerrainHeightAndType(globalX, globalZ);
      
      for (let y = 0; y <= Math.max(height, WATER_LEVEL); y++) {
        const key = `${globalX},${y},${globalZ}`;
        
        // Check if modified by player
        if (gameStore.modifiedBlocks.has(key)) {
          const modType = gameStore.modifiedBlocks.get(key);
          if (modType !== 0) {
            terrainGrid[key] = modType as number;
          }
          continue;
        }

        if (y <= height) {
          let type = BLOCK_TYPES.DIRT;
          
          if (biome === 'mountain') {
            if (y === height) {
              type = BLOCK_TYPES.SNOW;
            } else {
              type = BLOCK_TYPES.STONE;
            }
          } else if (biome === 'desert') {
            if (y === height) {
              type = BLOCK_TYPES.SAND;
            } else if (y > height - 3) {
              type = BLOCK_TYPES.SAND;
            } else {
              type = BLOCK_TYPES.STONE;
            }
          } else { // forest / plains
            if (y === height) {
              type = BLOCK_TYPES.GRASS;
            } else if (y > height - 3) {
              type = BLOCK_TYPES.DIRT;
            } else {
              type = BLOCK_TYPES.STONE;
            }
          }
          
          // Caves (3D noise)
          if (y < height - 1) {
            const caveNoise = noise3D(globalX * 0.1, y * 0.1, globalZ * 0.1);
            if (caveNoise > 0.4) {
              continue; // Cave air
            }
          }

          terrainGrid[key] = type;
        } else if (y <= WATER_LEVEL) {
          terrainGrid[key] = BLOCK_TYPES.WATER;
        }
      }
    }
  }

  // 2. Generate flora (Trees & Cacti) - looking at a slightly larger bounding box to catch boundary-crossing foliage
  const padding = 3;
  for (let gx = chunkStartX - padding; gx < chunkStartX + CHUNK_SIZE + padding; gx++) {
    for (let gz = chunkStartZ - padding; gz < chunkStartZ + CHUNK_SIZE + padding; gz++) {
      const { height, biome } = getTerrainHeightAndType(gx, gz);
      
      // Make sure it's above water level
      if (height <= WATER_LEVEL) continue;

      const spawnRoll = hash2D(gx, gz, globalSeed);

      if (biome === 'forest' && spawnRoll < 0.03) {
        // Spawn a tree
        const treeHeight = 5 + Math.floor(hash2D(gx, gz, globalSeed + 1) * 3);
        
        // Trunk
        for (let ty = 1; ty <= treeHeight; ty++) {
          const tx = gx;
          const tyPos = height + ty;
          const tz = gz;
          
          if (tx >= chunkStartX && tx < chunkStartX + CHUNK_SIZE &&
              tz >= chunkStartZ && tz < chunkStartZ + CHUNK_SIZE) {
            const key = `${tx},${tyPos},${tz}`;
            if (!gameStore.modifiedBlocks.has(key)) {
              terrainGrid[key] = BLOCK_TYPES.WOOD;
            }
          }
        }

        // Leaves
        const leafCenterY = height + treeHeight;
        for (let lx = -2; lx <= 2; lx++) {
          for (let lz = -2; lz <= 2; lz++) {
            for (let ly = -1; ly <= 1; ly++) {
              // Corner cutting
              if (Math.abs(lx) === 2 && Math.abs(lz) === 2 && hash2D(gx + lx, gz + lz, globalSeed + ly) < 0.5) continue;
              
              // Skip the trunk location at leaf levels
              if (lx === 0 && lz === 0 && ly <= 0) continue;

              const leafX = gx + lx;
              const leafY = leafCenterY + ly;
              const leafZ = gz + lz;

              if (leafX >= chunkStartX && leafX < chunkStartX + CHUNK_SIZE &&
                  leafZ >= chunkStartZ && leafZ < chunkStartZ + CHUNK_SIZE) {
                const key = `${leafX},${leafY},${leafZ}`;
                if (!gameStore.modifiedBlocks.has(key) && !terrainGrid[key]) {
                  terrainGrid[key] = BLOCK_TYPES.LEAVES;
                }
              }
            }
          }
        }
      } else if (biome === 'desert' && spawnRoll < 0.015) {
        // Spawn a cactus
        const cactusHeight = 3 + Math.floor(hash2D(gx, gz, globalSeed + 1) * 2);
        
        for (let cy = 1; cy <= cactusHeight; cy++) {
          const cx = gx;
          const cyPos = height + cy;
          const cz = gz;

          if (cx >= chunkStartX && cx < chunkStartX + CHUNK_SIZE &&
              cz >= chunkStartZ && cz < chunkStartZ + CHUNK_SIZE) {
            const key = `${cx},${cyPos},${cz}`;
            if (!gameStore.modifiedBlocks.has(key)) {
              terrainGrid[key] = BLOCK_TYPES.CACTUS;
            }
          }
        }
      }
    }
  }

  // 3. Process player placements outside normal generation bounds
  for (const [key, modType] of gameStore.modifiedBlocks.entries()) {
    if (modType === 0) continue;
    const [mx, my, mz] = key.split(',').map(Number);
    
    const mChunkX = Math.floor(mx / CHUNK_SIZE);
    const mChunkZ = Math.floor(mz / CHUNK_SIZE);
    if (mChunkX === chunkX && mChunkZ === chunkZ) {
      terrainGrid[key] = modType;
    }
  }

  // Convert grid to array
  Object.entries(terrainGrid).forEach(([key, type]) => {
    const [x, y, z] = key.split(',').map(Number);
    blocks.push({ position: [x, y, z], type });
  });

  return blocks;
}

