import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import http from "http";
import { Server } from "socket.io";
import { initTerrainGenerator, getTerrainHeightAndType } from "./src/utils/terrain";

async function startServer() {
  const app = express();
  const PORT = 3000;
  const server = http.createServer(app);
  const io = new Server(server, {
    cors: { origin: "*" },
  });

  // Track players and modified blocks
  const players = new Map();
  // key: "x,y,z", value: blockType (0 for removed, 1+ for block types)
  const modifiedBlocks = new Map();
  const seed = Math.random(); // Shared seed for terrain

  // Initialize terrain generator on server
  initTerrainGenerator(seed);

  // Helper to find ground height for mobs
  const getGroundHeight = (x: number, z: number) => {
    const rx = Math.round(x);
    const rz = Math.round(z);
    
    // Traverse y from 30 down to find highest solid block
    for (let y = 30; y >= 0; y--) {
      const key = `${rx},${y},${rz}`;
      if (modifiedBlocks.has(key)) {
        if (modifiedBlocks.get(key) !== 0) return y + 1.0;
        continue;
      }
      
      const { height } = getTerrainHeightAndType(rx, rz);
      if (y <= height) {
        return y + 1.0;
      }
    }
    return 1.0;
  };

  // Mobs setup
  interface Mob {
    id: string;
    type: 'pig' | 'creeper' | 'zombie';
    position: [number, number, number];
    rotation: [number, number, number];
    targetPos?: [number, number];
  }

  const mobs: Mob[] = [];
  const mobTypes: ('pig' | 'creeper' | 'zombie')[] = ['pig', 'creeper', 'zombie'];
  for (let i = 0; i < 12; i++) {
    const type = mobTypes[i % mobTypes.length];
    const x = 16 + Math.random() * 32;
    const z = 16 + Math.random() * 32;
    const groundY = getGroundHeight(x, z);
    mobs.push({
      id: `mob_${i}`,
      type,
      position: [x, groundY, z],
      rotation: [0, Math.random() * Math.PI * 2, 0]
    });
  }

  // Mob tick simulation (10Hz)
  setInterval(() => {
    const delta = 0.1;
    const GRAVITY = 15;
    
    mobs.forEach(mob => {
      // Wandering AI
      if (!mob.targetPos || Math.random() < 0.05) {
        mob.targetPos = [
          mob.position[0] + (Math.random() - 0.5) * 12,
          mob.position[2] + (Math.random() - 0.5) * 12
        ];
      }
      
      const dx = mob.targetPos[0] - mob.position[0];
      const dz = mob.targetPos[1] - mob.position[2];
      const dist = Math.sqrt(dx * dx + dz * dz);
      
      if (dist > 0.5) {
        const speed = mob.type === 'pig' ? 1.5 : mob.type === 'zombie' ? 1.0 : 1.2;
        mob.position[0] += (dx / dist) * speed * delta;
        mob.position[2] += (dz / dist) * speed * delta;
        mob.rotation[1] = Math.atan2(dx, dz);
      } else {
        mob.targetPos = undefined;
      }
      
      // Physics
      mob.position[1] -= GRAVITY * delta;
      
      // Collision
      const groundY = getGroundHeight(mob.position[0], mob.position[2]);
      if (mob.position[1] < groundY) {
        mob.position[1] = groundY;
      }
    });
    
    io.emit("mobsUpdate", mobs);
  }, 100);

  io.on("connection", (socket) => {
    // New player joined
    players.set(socket.id, { id: socket.id, position: [0, 50, 0], rotation: [0, 0, 0] });
    
    // Send initial state to the new player
    socket.emit("init", {
      seed,
      players: Array.from(players.values()),
      modifiedBlocks: Array.from(modifiedBlocks.entries()),
      mobs
    });

    // Notify others
    socket.broadcast.emit("playerJoin", players.get(socket.id));

    socket.on("move", (data) => {
      if (players.has(socket.id)) {
        const p = players.get(socket.id);
        p.position = data.position;
        p.rotation = data.rotation;
        // Broadcast movement to others
        socket.broadcast.emit("playerMove", { id: socket.id, position: data.position, rotation: data.rotation });
      }
    });

    socket.on("setBlock", (data) => {
      // data: { x, y, z, type }
      const key = `${data.x},${data.y},${data.z}`;
      modifiedBlocks.set(key, data.type);
      socket.broadcast.emit("blockChanged", data);
    });

    socket.on("disconnect", () => {
      players.delete(socket.id);
      socket.broadcast.emit("playerLeave", socket.id);
    });
  });

  // API routes
  app.get("/api/health", (req, res) => {
    res.json({ status: "ok" });
  });

  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  server.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://0.0.0.0:${PORT}`);
  });
}

startServer();

