// Simple observable store to avoid heavy React Context rerenders
type Listener = () => void;

class Store {
  seed: number = 0;
  players: Map<string, { position: [number, number, number]; rotation: [number, number, number] }> = new Map();
  modifiedBlocks: Map<string, number> = new Map();
  listeners: Set<Listener> = new Set();
  
  // Local active block selection
  selectedBlockType: number = 1;

  subscribe(listener: Listener) {
    this.listeners.add(listener);
    return () => { this.listeners.delete(listener); };
  }

  emit() {
    for (const listener of this.listeners) {
      listener();
    }
  }

  setSeed(seed: number) {
    this.seed = seed;
  }

  setPlayer(id: string, state: { position: [number, number, number]; rotation: [number, number, number] }) {
    this.players.set(id, state);
    this.emit();
  }

  removePlayer(id: string) {
    this.players.delete(id);
    this.emit();
  }

  setModifiedBlock(x: number, y: number, z: number, type: number) {
    this.modifiedBlocks.set(`${x},${y},${z}`, type);
    this.emit();
  }
}

export const gameStore = new Store();
